/* ═══════════ Design tokens ═══════════ */
:root {
  --bg: #f4f6fb;
  --surface: #ffffff;
  --surface-2: #f0f3f9;
  --border: #e3e8f2;
  --text: #16213a;
  --text-2: #5b6b8c;
  --text-3: #8a97b5;
  --accent: #3b6ef0;
  --accent-hover: #2f5cd6;
  --accent-soft: #e8effe;
  --danger: #e14b4b;
  --shadow: 0 1px 2px rgb(22 33 58 / .06), 0 8px 24px rgb(22 33 58 / .07);
  --shadow-lg: 0 12px 48px rgb(22 33 58 / .18);
  --radius: 14px;
  --radius-sm: 9px;

  --st-draft:      #8494ad;
  --st-submitted:  #3b6ef0;
  --st-review:     #e39a2d;
  --st-info:       #9b59e6;
  --st-approved:   #27ae72;
  --st-denied:     #e14b4b;
  --st-paid:       #13a3a3;
}

[data-theme="dark"] {
  --bg: #0f1420;
  --surface: #171e30;
  --surface-2: #1e2740;
  --border: #2a3552;
  --text: #e8edf8;
  --text-2: #9daccc;
  --text-3: #6b7a9e;
  --accent: #5c85ff;
  --accent-hover: #7498ff;
  --accent-soft: #233159;
  --shadow: 0 1px 2px rgb(0 0 0 / .3), 0 8px 24px rgb(0 0 0 / .35);
  --shadow-lg: 0 12px 48px rgb(0 0 0 / .55);
}

* { box-sizing: border-box; }

html, body { margin: 0; padding: 0; }

body {
  font-family: "Inter", system-ui, -apple-system, sans-serif;
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
  transition: background .25s, color .25s;
}

/* ═══════════ Top bar ═══════════ */
.topbar {
  display: flex; align-items: center; justify-content: space-between;
  gap: 16px; flex-wrap: wrap;
  padding: 18px clamp(16px, 4vw, 44px);
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  position: sticky; top: 0; z-index: 30;
}
.brand { display: flex; align-items: center; gap: 12px; }
.brand-mark {
  font-size: 26px; width: 48px; height: 48px;
  display: grid; place-items: center;
  background: var(--accent-soft); border-radius: 12px;
}
.brand h1 { font-size: 20px; margin: 0; font-weight: 800; letter-spacing: -.02em; }
.brand-sub { margin: 0; font-size: 12.5px; color: var(--text-2); }
.topbar-actions { display: flex; gap: 8px; align-items: center; }

/* ═══════════ Buttons ═══════════ */
.btn {
  font: inherit; font-weight: 600; font-size: 14px;
  border: 1px solid transparent; border-radius: var(--radius-sm);
  padding: 9px 16px; cursor: pointer;
  transition: background .15s, color .15s, border-color .15s, transform .05s;
  white-space: nowrap;
}
.btn:active { transform: translateY(1px); }
.btn-primary { background: var(--accent); color: #fff; }
.btn-primary:hover { background: var(--accent-hover); }
.btn-ghost { background: transparent; color: var(--text-2); border-color: var(--border); }
.btn-ghost:hover { background: var(--surface-2); color: var(--text); }
.btn-icon { padding: 9px 11px; }
.btn-danger { background: transparent; color: var(--danger); border-color: var(--border); }
.btn-danger:hover { background: color-mix(in srgb, var(--danger) 10%, transparent); }

/* ═══════════ Layout ═══════════ */
.container { max-width: 1080px; margin: 0 auto; padding: 26px clamp(16px, 4vw, 44px) 80px; }

/* ═══════════ Stats ═══════════ */
.stats-grid {
  display: grid; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
  gap: 14px; margin-bottom: 24px;
}
.stat-card {
  background: var(--surface); border: 1px solid var(--border);
  border-radius: var(--radius); padding: 16px 18px; box-shadow: var(--shadow);
}
.stat-label { font-size: 12px; font-weight: 600; text-transform: uppercase; letter-spacing: .06em; color: var(--text-3); margin: 0 0 6px; }
.stat-value { font-size: 24px; font-weight: 800; letter-spacing: -.02em; margin: 0; }
.stat-value small { font-size: 13px; font-weight: 600; color: var(--text-2); }
.stat-dot { display: inline-block; width: 8px; height: 8px; border-radius: 50%; margin-right: 6px; }

/* ═══════════ Toolbar ═══════════ */
.toolbar { display: flex; flex-wrap: wrap; gap: 12px; align-items: center; margin-bottom: 18px; }
.search-wrap { position: relative; flex: 1 1 240px; }
.search-icon { position: absolute; left: 12px; top: 50%; transform: translateY(-50%); font-size: 13px; opacity: .55; pointer-events: none; }
.search-wrap input {
  width: 100%; font: inherit; font-size: 14px;
  padding: 10px 12px 10px 36px;
  background: var(--surface); color: var(--text);
  border: 1px solid var(--border); border-radius: var(--radius-sm);
}
.search-wrap input:focus { outline: 2px solid var(--accent); outline-offset: -1px; }

.chip-row { display: flex; gap: 6px; flex-wrap: wrap; }
.chip {
  font: inherit; font-size: 12.5px; font-weight: 600;
  padding: 7px 13px; border-radius: 999px; cursor: pointer;
  background: var(--surface); color: var(--text-2);
  border: 1px solid var(--border);
  transition: all .15s;
}
.chip:hover { border-color: var(--text-3); }
.chip.active { background: var(--accent); border-color: var(--accent); color: #fff; }
.chip .count { opacity: .65; font-weight: 500; margin-left: 4px; }

.toolbar-right { display: flex; gap: 8px; margin-left: auto; }
.select {
  font: inherit; font-size: 13.5px; font-weight: 500;
  padding: 9px 10px; border-radius: var(--radius-sm);
  background: var(--surface); color: var(--text);
  border: 1px solid var(--border); cursor: pointer;
}

/* ═══════════ Claim cards ═══════════ */
.claim-list { display: flex; flex-direction: column; gap: 10px; }
.claim-card {
  display: grid; grid-template-columns: 1fr auto; gap: 4px 18px;
  background: var(--surface); border: 1px solid var(--border);
  border-radius: var(--radius); padding: 16px 20px;
  box-shadow: var(--shadow); cursor: pointer;
  transition: border-color .15s, transform .12s;
  animation: rise .25s ease both;
}
.claim-card:hover { border-color: var(--accent); transform: translateY(-1px); }
@keyframes rise { from { opacity: 0; transform: translateY(6px); } }

.claim-main { min-width: 0; }
.claim-title-row { display: flex; align-items: center; gap: 10px; flex-wrap: wrap; }
.claim-title { font-size: 15.5px; font-weight: 700; margin: 0; }
.claim-meta { font-size: 13px; color: var(--text-2); margin: 5px 0 0; display: flex; flex-wrap: wrap; gap: 4px 14px; }
.claim-tags { margin-top: 8px; display: flex; gap: 6px; flex-wrap: wrap; }

.claim-side { text-align: right; display: flex; flex-direction: column; align-items: flex-end; gap: 8px; }
.claim-amount { font-size: 17px; font-weight: 800; letter-spacing: -.01em; }
.claim-amount.none { color: var(--text-3); font-weight: 500; font-size: 13.5px; }
.claim-date { font-size: 12px; color: var(--text-3); }

/* ═══════════ Badges ═══════════ */
.badge {
  display: inline-flex; align-items: center; gap: 5px;
  font-size: 11.5px; font-weight: 700; letter-spacing: .02em;
  padding: 4px 10px; border-radius: 999px;
  color: var(--badge-c, #666); background: color-mix(in srgb, var(--badge-c, #666) 13%, transparent);
