}
.tag {
  font-size: 11.5px; padding: 3px 9px; border-radius: 999px;
  background: var(--accent-soft); color: var(--accent); font-weight: 600;
}

/* ═══════════ Empty state ═══════════ */
.empty-state { text-align: center; padding: 70px 20px; }
.empty-art { font-size: 52px; margin-bottom: 12px; }
.empty-state h2 { margin: 0 0 6px; font-size: 20px; }
.empty-state p { color: var(--text-2); margin: 0 0 20px; }

/* ═══════════ Overlays / modal / drawer ═══════════ */
.overlay {
  position: fixed; inset: 0; z-index: 50;
  background: rgb(10 16 32 / .5);
  display: grid; place-items: center; padding: 20px;
  animation: fade .18s ease;
}
.overlay-right { place-items: stretch end; padding: 0; }
@keyframes fade { from { opacity: 0; } }

.modal {
  width: min(620px, 100%); max-height: 90vh; overflow-y: auto;
  background: var(--surface); border-radius: var(--radius);
  box-shadow: var(--shadow-lg); padding: 24px 26px;
  animation: pop .2s ease;
}
@keyframes pop { from { opacity: 0; transform: scale(.96) translateY(8px); } }
.modal-head { display: flex; align-items: center; justify-content: space-between; margin-bottom: 18px; }
.modal-head h2 { margin: 0; font-size: 19px; }

.drawer {
