.field textarea { resize: vertical; }
.form-error { color: var(--danger); font-size: 13.5px; font-weight: 600; margin: 14px 0 0; }
.modal-actions { display: flex; justify-content: flex-end; gap: 8px; margin-top: 20px; }

/* ═══════════ Detail drawer ═══════════ */
.detail-head { display: flex; justify-content: space-between; align-items: flex-start; gap: 12px; margin-bottom: 4px; }
.detail-head h2 { margin: 0; font-size: 21px; letter-spacing: -.01em; }
.detail-badges { display: flex; gap: 6px; flex-wrap: wrap; margin: 10px 0 16px; }
.detail-amount { font-size: 26px; font-weight: 800; margin: 0 0 4px; }
.detail-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px 18px; margin: 18px 0; }
.detail-item { font-size: 13px; }
.detail-item .k { color: var(--text-3); font-weight: 600; text-transform: uppercase; font-size: 11px; letter-spacing: .05em; margin-bottom: 3px; }
.detail-desc { background: var(--surface-2); border-radius: var(--radius-sm); padding: 13px 15px; font-size: 14px; line-height: 1.55; color: var(--text-2); white-space: pre-wrap; }
.detail-actions { display: flex; gap: 8px; flex-wrap: wrap; margin: 20px 0; }

.section-title { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: .06em; color: var(--text-3); margin: 26px 0 12px; display: flex; align-items: center; justify-content: space-between; }
.section-title .btn { padding: 5px 10px; font-size: 12px; }

.status-stepper { display: flex; gap: 6px; flex-wrap: wrap; }
.status-step {
  font: inherit; font-size: 12px; font-weight: 700;
  padding: 7px 12px; border-radius: 999px; cursor: pointer;
  background: var(--surface-2); color: var(--text-2);
  border: 1.5px solid var(--border); transition: all .15s;
}
.status-step:hover { border-color: var(--text-3); }
.status-step.active { color: #fff; background: var(--step-c); border-color: var(--step-c); }

/* Timeline */
.timeline { list-style: none; margin: 0; padding: 0 0 0 8px; }
.timeline li { position: relative; padding: 0 0 18px 24px; border-left: 2px solid var(--border); }
.timeline li:last-child { padding-bottom: 2px; }
.timeline li::before {
  content: ""; position: absolute; left: -7px; top: 4px;
  width: 10px; height: 10px; border-radius: 50%;
  background: var(--tl-c, var(--accent)); border: 2px solid var(--surface);
  box-shadow: 0 0 0 2px var(--tl-c, var(--accent));
}
.tl-kind { font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: .05em; color: var(--tl-c, var(--accent)); }
.tl-text { font-size: 14px; margin: 2px 0; }
.tl-time { font-size: 12px; color: var(--text-3); }

/* Notes */
.note { background: var(--surface-2); border-radius: var(--radius-sm); padding: 11px 14px; margin-bottom: 10px; }
.note-text { font-size: 14px; margin: 0 0 5px; white-space: pre-wrap; }
.note-meta { font-size: 12px; color: var(--text-3); display: flex; justify-content: space-between; gap: 8px; }
.note-meta button { background: none; border: none; color: var(--danger); cursor: pointer; font: inherit; font-size: 12px; padding: 0; }
.note-form { display: flex; gap: 8px; margin-top: 4px; }
.note-form input {
  flex: 1; font: inherit; font-size: 14px; color: var(--text);
  background: var(--bg); border: 1px solid var(--border);
  border-radius: var(--radius-sm); padding: 9px 11px;
}

/* ═══════════ Toasts ═══════════ */
.toast-stack { position: fixed; bottom: 22px; right: 22px; z-index: 90; display: flex; flex-direction: column; gap: 8px; }
.toast {
  background: var(--text); color: var(--bg);
  font-size: 14px; font-weight: 600;
  padding: 12px 18px; border-radius: var(--radius-sm);
  box-shadow: var(--shadow-lg);
  animation: toast-in .25s ease;
}
.toast.out { animation: toast-out .3s ease forwards; }
@keyframes toast-in { from { opacity: 0; transform: translateY(10px); } }
@keyframes toast-out { to { opacity: 0; transform: translateY(10px); } }

/* ═══════════ Responsive ═══════════ */
@media (max-width: 640px) {
  .claim-card { grid-template-columns: 1fr; }
  .claim-side { text-align: left; align-items: flex-start; flex-direction: row; align-items: center; justify-content: space-between; }
  .form-grid { grid-template-columns: 1fr; }
  .field.span-2 { grid-column: span 1; }
  .toolbar-right { margin-left: 0; width: 100%; }
  .toolbar-right .select { flex: 1; }
}
