"use strict";

/* ═══════════════ Constants ═══════════════ */
const STATUSES = ["Draft", "Submitted", "Under Review", "Info Needed", "Approved", "Denied", "Paid"];
const STATUS_COLORS = {
  "Draft": "var(--st-draft)",
  "Submitted": "var(--st-submitted)",
  "Under Review": "var(--st-review)",
  "Info Needed": "var(--st-info)",
  "Approved": "var(--st-approved)",
  "Denied": "var(--st-denied)",
  "Paid": "var(--st-paid)",
};
const TYPES = ["Auto", "Home", "Health", "Life", "Travel", "Pet", "Other"];
const TYPE_ICONS = { Auto: "🚗", Home: "🏠", Health: "🩺", Life: "❤️", Travel: "✈️", Pet: "🐾", Other: "📋" };
const OPEN_STATUSES = new Set(["Draft", "Submitted", "Under Review", "Info Needed"]);
const LS_KEY = "claimdesk.claims.v1";
const THEME_KEY = "claimdesk.theme";

/* ═══════════════ Store ═══════════════ */
const store = {
  claims: [],
  load() {
    try {
      const raw = localStorage.getItem(LS_KEY);
      this.claims = raw ? JSON.parse(raw) : null;
    } catch { this.claims = null; }
    if (!Array.isArray(this.claims)) {
      this.claims = seedClaims();
      this.save();
    }
  },
  save() { localStorage.setItem(LS_KEY, JSON.stringify(this.claims)); },
  byId(id) { return this.claims.find(c => c.id === id); },
};

const uid = () => Date.now().toString(36) + Math.random().toString(36).slice(2, 8);

function seedClaims() {
  const now = Date.now(), day = 864e5;
  const iso = t => new Date(t).toISOString();
