      id: uid(),
      notes: [],
      tags: [],
      createdAt: iso(filed),
      updatedAt: iso(filed + (events?.length ? 2 : 0) * day),
      timeline: events || [{ at: iso(filed), kind: "created", text: "Claim created" }],
      ...over,
    };
  };
  return [
    mk({
      title: "Rear-end collision on I-95", type: "Auto", status: "Under Review",
      provider: "Acme Insurance Co.", claimNumber: "AUTO-2026-1187", amount: 4320.5,
      incidentDate: isoDate(now - 12 * day), filedDate: isoDate(now - 10 * day),
      description: "Rear-ended at a stoplight. Other driver cited. Bumper and trunk damage; whiplash checked out OK.",
      tags: ["car", "collision"],
      notes: [{ id: uid(), text: "Adjuster call scheduled for Tuesday.", at: iso(now - 3 * day) }],
    }, 10, [
      { at: iso(now - 10 * day), kind: "created", text: "Claim created" },
      { at: iso(now - 10 * day), kind: "status", text: "Status changed to Submitted" },
      { at: iso(now - 4 * day), kind: "status", text: "Status changed to Under Review" },
    ]),
    mk({
      title: "Kitchen water damage", type: "Home", status: "Info Needed",
      provider: "Hearthstone Mutual", claimNumber: "HM-88412", amount: 12800,
      incidentDate: isoDate(now - 21 * day), filedDate: isoDate(now - 18 * day),
      description: "Dishwasher supply line burst overnight. Flooring and lower cabinets damaged.",
      tags: ["water", "urgent"],
    }, 18, [
      { at: iso(now - 18 * day), kind: "created", text: "Claim created" },
      { at: iso(now - 18 * day), kind: "status", text: "Status changed to Submitted" },
      { at: iso(now - 6 * day), kind: "status", text: "Status changed to Under Review" },
      { at: iso(now - 2 * day), kind: "status", text: "Status changed to Info Needed — insurer requested plumber's report" },
    ]),
    mk({
      title: "Emergency room visit", type: "Health", status: "Paid",
      provider: "Vitalis Health", claimNumber: "VH-2026-33981", amount: 1865.75,
      incidentDate: isoDate(now - 45 * day), filedDate: isoDate(now - 42 * day),
      description: "Sprained ankle during a weekend hike. X-rays negative.",
      tags: ["er"],
    }, 42, [
      { at: iso(now - 42 * day), kind: "created", text: "Claim created" },
      { at: iso(now - 42 * day), kind: "status", text: "Status changed to Submitted" },
      { at: iso(now - 30 * day), kind: "status", text: "Status changed to Approved" },
      { at: iso(now - 25 * day), kind: "status", text: "Status changed to Paid" },
    ]),
    mk({
      title: "Cancelled flight to Lisbon", type: "Travel", status: "Denied",
      provider: "WanderSure", claimNumber: "WS-77120", amount: 640,
      incidentDate: isoDate(now - 60 * day), filedDate: isoDate(now - 55 * day),
