    }, 55, [
      { at: iso(now - 55 * day), kind: "created", text: "Claim created" },
      { at: iso(now - 55 * day), kind: "status", text: "Status changed to Submitted" },
      { at: iso(now - 38 * day), kind: "status", text: "Status changed to Denied — reason: staffing cancellations excluded" },
    ]),
    mk({
      title: "Dog surgery — torn ACL", type: "Pet", status: "Draft",
      provider: "Pawsure", claimNumber: "", amount: 3900,
      incidentDate: isoDate(now - 2 * day), filedDate: isoDate(now),
      description: "Biscuit tore his ACL at the dog park. Gathering vet invoices before submitting.",
      tags: ["biscuit", "surgery"],
    }, 0),
  ];
}

function isoDate(t) { return new Date(t).toISOString().slice(0, 10); }

/* ═══════════════ UI state ═══════════════ */
const ui = { search: "", status: "", type: "", sort: "updated-desc", drawerClaimId: null };

/* ═══════════════ DOM refs ═══════════════ */
const $ = sel => document.querySelector(sel);
const statsGrid = $("#statsGrid"), claimList = $("#claimList"), emptyState = $("#emptyState");
const claimModal = $("#claimModal"), claimForm = $("#claimForm"), detailDrawer = $("#detailDrawer");
const drawerBody = $("#drawerBody"), toastStack = $("#toastStack");

/* ═══════════════ Helpers ═══════════════ */
const fmtMoney = n => n == null || n === "" || isNaN(n) ? null
  : Number(n).toLocaleString(undefined, { style: "currency", currency: "USD", maximumFractionDigits: 2 });
const fmtDate = d => d ? new Date(d + (d.length === 10 ? "T12:00:00" : "")).toLocaleDateString(undefined, { month: "short", day: "numeric", year: "numeric" }) : "—";
const fmtDateTime = d => new Date(d).toLocaleString(undefined, { month: "short", day: "numeric", hour: "numeric", minute: "2-digit" });
const esc = s => String(s ?? "").replace(/[&<>"']/g, c => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c]));

function toast(msg) {
  const el = document.createElement("div");
  el.className = "toast"; el.textContent = msg;
  toastStack.appendChild(el);
  setTimeout(() => { el.classList.add("out"); setTimeout(() => el.remove(), 320); }, 2400);
}

/* ═══════════════ Filtering / sorting ═══════════════ */
function visibleClaims() {
  const q = ui.search.trim().toLowerCase();
  let list = store.claims.filter(c => {
    if (ui.status && c.status !== ui.status) return false;
    if (ui.type && c.type !== ui.type) return false;
    if (q) {
      const hay = [c.title, c.provider, c.claimNumber, c.description, ...(c.tags || [])].join(" ").toLowerCase();
      if (!hay.includes(q)) return false;
    }
    return true;
  });
  const byAmount = (a, b) => (b.amount || 0) - (a.amount || 0);
  const sorters = {
    "updated-desc": (a, b) => new Date(b.updatedAt) - new Date(a.updatedAt),
    "filed-desc": (a, b) => (b.filedDate || "").localeCompare(a.filedDate || ""),
    "filed-asc": (a, b) => (a.filedDate || "").localeCompare(b.filedDate || ""),
    "amount-desc": byAmount,
    "amount-asc": (a, b) => byAmount(b, a),
    "title-asc": (a, b) => a.title.localeCompare(b.title),
  };
  return list.sort(sorters[ui.sort] || sorters["updated-desc"]);
}

/* ═══════════════ Render ═══════════════ */
function renderStats() {
  const claims = store.claims;
  const open = claims.filter(c => OPEN_STATUSES.has(c.status));
  const openAmount = open.reduce((s, c) => s + (Number(c.amount) || 0), 0);
  const paidAmount = claims.filter(c => c.status === "Paid").reduce((s, c) => s + (Number(c.amount) || 0), 0);
  const needsInfo = claims.filter(c => c.status === "Info Needed").length;
  const cards = [
    { label: "Total claims", value: claims.length },
    { label: "Open", value: open.length, dot: "var(--st-submitted)", sub: openAmount ? fmtMoney(openAmount) + " pending" : "" },
    { label: "Info needed", value: needsInfo, dot: "var(--st-info)" },
    { label: "Paid out", value: fmtMoney(paidAmount) || "$0", dot: "var(--st-paid)" },
  ];
  statsGrid.innerHTML = cards.map(c => `
    <div class="stat-card">
      <p class="stat-label">${c.dot ? `<span class="stat-dot" style="background:${c.dot}"></span>` : ""}${c.label}</p>
      <p class="stat-value">${c.value} ${c.sub ? `<small>· ${c.sub}</small>` : ""}</p>
    </div>`).join("");
}

function renderChips() {
  const counts = {};
  store.claims.forEach(c => counts[c.status] = (counts[c.status] || 0) + 1);
  const total = store.claims.length;
  const chip = (val, label, count) =>
    `<button class="chip ${ui.status === val ? "active" : ""}" data-status="${esc(val)}">${label}<span class="count">${count}</span></button>`;
  $("#statusChips").innerHTML =
    chip("", "All", total) +
    STATUSES.filter(s => counts[s]).map(s => chip(s, s, counts[s])).join("");
}

function renderTypeFilter() {
  const sel = $("#typeFilter");
  const cur = ui.type;
  sel.innerHTML = `<option value="">All types</option>` +
    TYPES.map(t => `<option ${t === cur ? "selected" : ""}>${t}</option>`).join("");
}

function renderList() {
  const list = visibleClaims();
  claimList.innerHTML = list.map((c, i) => {
    const amount = fmtMoney(c.amount);
    return `
    <article class="claim-card" data-id="${c.id}" style="animation-delay:${Math.min(i * 30, 240)}ms" tabindex="0" role="button" aria-label="Open ${esc(c.title)}">
      <div class="claim-main">
        <div class="claim-title-row">
          <span class="type-pill">${TYPE_ICONS[c.type] || "📋"} ${esc(c.type)}</span>
          <h3 class="claim-title">${esc(c.title)}</h3>
        </div>
        <p class="claim-meta">
          ${c.provider ? `<span>🏢 ${esc(c.provider)}</span>` : ""}
          ${c.claimNumber ? `<span>#${esc(c.claimNumber)}</span>` : ""}
          <span>Filed ${fmtDate(c.filedDate)}</span>
        </p>
        ${(c.tags || []).length ? `<div class="claim-tags">${c.tags.map(t => `<span class="tag">${esc(t)}</span>`).join("")}</div>` : ""}
      </div>
      <div class="claim-side">
        <span class="badge" style="--badge-c:${STATUS_COLORS[c.status]}">${esc(c.status)}</span>
        ${amount ? `<span class="claim-amount">${amount}</span>` : `<span class="claim-amount none">No amount</span>`}
        <span class="claim-date">Updated ${fmtDateTime(c.updatedAt)}</span>
      </div>
    </article>`;
  }).join("");
  emptyState.hidden = list.length > 0;
}

function renderAll() {
  renderStats();
  renderChips();
  renderTypeFilter();
  renderList();
  if (ui.drawerClaimId) renderDrawer(ui.drawerClaimId);
}

/* ═══════════════ Modal (create / edit) ═══════════════ */
function fillSelect(sel, options, value) {
  sel.innerHTML = options.map(o => `<option ${o === value ? "selected" : ""}>${o}</option>`).join("");
}

function openModal(claim) {
  $("#modalTitle").textContent = claim ? "Edit Claim" : "New Claim";
  $("#formError").hidden = true;
  fillSelect($("#fType"), TYPES, claim?.type || "Auto");
  fillSelect($("#fStatus"), STATUSES, claim?.status || "Draft");
  $("#claimId").value = claim?.id || "";
  $("#fTitle").value = claim?.title || "";
  $("#fProvider").value = claim?.provider || "";
  $("#fClaimNumber").value = claim?.claimNumber || "";
  $("#fAmount").value = claim?.amount ?? "";
  $("#fIncidentDate").value = claim?.incidentDate || "";
  $("#fFiledDate").value = claim?.filedDate || isoDate(Date.now());
  $("#fTags").value = (claim?.tags || []).join(", ");
  $("#fDescription").value = claim?.description || "";
  claimModal.hidden = false;
  $("#fTitle").focus();
}

function closeModal() { claimModal.hidden = true; }

claimForm.addEventListener("submit", e => {
  e.preventDefault();
  const title = $("#fTitle").value.trim();
  const filedDate = $("#fFiledDate").value;
  if (!title) return formError("Title is required.");
  if (!filedDate) return formError("Date filed is required.");

  const id = $("#claimId").value;
  const status = $("#fStatus").value;
  const nowIso = new Date().toISOString();
  const data = {
    title,
    type: $("#fType").value,
    status,
    provider: $("#fProvider").value.trim(),
    claimNumber: $("#fClaimNumber").value.trim(),
    amount: $("#fAmount").value === "" ? null : Number($("#fAmount").value),
    incidentDate: $("#fIncidentDate").value,
    filedDate,
    tags: $("#fTags").value.split(",").map(t => t.trim()).filter(Boolean),
    description: $("#fDescription").value.trim(),
    updatedAt: nowIso,
  };

  if (id) {
    const claim = store.byId(id);
    const statusChanged = claim.status !== status;
    Object.assign(claim, data);
    if (statusChanged) {
      claim.timeline.push({ at: nowIso, kind: "status", text: `Status changed to ${status}` });
    } else {
      claim.timeline.push({ at: nowIso, kind: "edit", text: "Claim details updated" });
    }
    toast("Claim updated");
  } else {
    const claim = {
      id: uid(), createdAt: nowIso, notes: [], ...data,
      timeline: [{ at: nowIso, kind: "created", text: "Claim created" }],
    };
    if (status !== "Draft") claim.timeline.push({ at: nowIso, kind: "status", text: `Status changed to ${status}` });
    store.claims.unshift(claim);
    toast("Claim created");
  }
  store.save();
  closeModal();
  renderAll();
});

function formError(msg) {
  const el = $("#formError");
  el.textContent = msg;
  el.hidden = false;
}

/* ═══════════════ Detail drawer ═══════════════ */
const TL_COLORS = { created: "var(--st-draft)", status: "var(--accent)", edit: "var(--st-review)" };

function renderDrawer(id) {
  const c = store.byId(id);
  if (!c) return closeDrawer();
  const amount = fmtMoney(c.amount);
  const timeline = [...(c.timeline || [])].reverse();
  drawerBody.innerHTML = `
    <div class="detail-head">
      <h2 id="drawerTitle">${esc(c.title)}</h2>
      <button class="btn btn-ghost btn-icon" data-close-drawer aria-label="Close">✕</button>
    </div>
    <div class="detail-badges">
      <span class="badge" style="--badge-c:${STATUS_COLORS[c.status]}">${esc(c.status)}</span>
      <span class="type-pill">${TYPE_ICONS[c.type] || "📋"} ${esc(c.type)}</span>
      ${(c.tags || []).map(t => `<span class="tag">${esc(t)}</span>`).join("")}
    </div>
    ${amount ? `<p class="detail-amount">${amount}</p>` : ""}
    <div class="detail-grid">
      <div class="detail-item"><div class="k">Provider</div>${esc(c.provider) || "—"}</div>
      <div class="detail-item"><div class="k">Claim #</div>${esc(c.claimNumber) || "—"}</div>
      <div class="detail-item"><div class="k">Incident date</div>${fmtDate(c.incidentDate)}</div>
      <div class="detail-item"><div class="k">Date filed</div>${fmtDate(c.filedDate)}</div>
    </div>
    ${c.description ? `<div class="detail-desc">${esc(c.description)}</div>` : ""}

    <div class="detail-actions">
      <button class="btn btn-primary" data-action="edit">✏️ Edit</button>
      <button class="btn btn-danger" data-action="delete">🗑 Delete</button>
    </div>

    <h3 class="section-title">Update status</h3>
    <div class="status-stepper">
      ${STATUSES.map(s => `<button class="status-step ${s === c.status ? "active" : ""}" style="--step-c:${STATUS_COLORS[s]}" data-set-status="${esc(s)}">${s}</button>`).join("")}
    </div>

    <h3 class="section-title">Timeline</h3>
    <ul class="timeline">
      ${timeline.map(ev => `
        <li style="--tl-c:${TL_COLORS[ev.kind] || "var(--accent)"}">
          <div class="tl-kind">${esc(ev.kind)}</div>
          <div class="tl-text">${esc(ev.text)}</div>
          <div class="tl-time">${fmtDateTime(ev.at)}</div>
        </li>`).join("")}
    </ul>

    <h3 class="section-title">Notes (${(c.notes || []).length})</h3>
    <div>
      ${(c.notes || []).slice().reverse().map(n => `
        <div class="note">
          <p class="note-text">${esc(n.text)}</p>
          <div class="note-meta"><span>${fmtDateTime(n.at)}</span><button data-del-note="${n.id}">Delete</button></div>
        </div>`).join("")}
      <form class="note-form" id="noteForm">
        <input id="noteInput" placeholder="Add a note… (e.g. called adjuster)" maxlength="300" required>
        <button class="btn btn-primary" type="submit">Add</button>
      </form>
    </div>`;
}

function openDrawer(id) {
  ui.drawerClaimId = id;
  renderDrawer(id);
  detailDrawer.hidden = false;
}

function closeDrawer() {
  ui.drawerClaimId = null;
  detailDrawer.hidden = true;
}

function setStatus(claim, status) {
  if (claim.status === status) return;
  claim.status = status;
  const nowIso = new Date().toISOString();
  claim.updatedAt = nowIso;
  claim.timeline.push({ at: nowIso, kind: "status", text: `Status changed to ${status}` });
  store.save();
  renderAll();
  toast(`Status → ${status}`);
}

drawerBody.addEventListener("click", e => {
  const close = e.target.closest("[data-close-drawer]");
  if (close) return closeDrawer();

  const step = e.target.closest("[data-set-status]");
  if (step) {
    const c = store.byId(ui.drawerClaimId);
    if (c) setStatus(c, step.dataset.setStatus);
    return;
  }

  const action = e.target.closest("[data-action]");
  if (action?.dataset.action === "edit") {
    const c = store.byId(ui.drawerClaimId);
    if (c) { closeDrawer(); openModal(c); }
    return;
  }
  if (action?.dataset.action === "delete") {
    const c = store.byId(ui.drawerClaimId);
    if (c && confirm(`Delete claim “${c.title}”? This cannot be undone.`)) {
      store.claims = store.claims.filter(x => x.id !== c.id);
      store.save();
      closeDrawer();
      renderAll();
      toast("Claim deleted");
    }
    return;
  }

  const delNote = e.target.closest("[data-del-note]");
  if (delNote) {
    const c = store.byId(ui.drawerClaimId);
    if (c) {
      c.notes = c.notes.filter(n => n.id !== delNote.dataset.delNote);
      c.updatedAt = new Date().toISOString();
      store.save();
      renderAll();
    }
  }
});

drawerBody.addEventListener("submit", e => {
  if (e.target.id !== "noteForm") return;
  e.preventDefault();
  const c = store.byId(ui.drawerClaimId);
  const input = $("#noteInput");
  const text = input.value.trim();
  if (!c || !text) return;
  const nowIso = new Date().toISOString();
  c.notes.push({ id: uid(), text, at: nowIso });
  c.updatedAt = nowIso;
  c.timeline.push({ at: nowIso, kind: "edit", text: `Note added: “${text.slice(0, 60)}${text.length > 60 ? "…" : ""}”` });
  store.save();
  renderAll();
  toast("Note added");
});

/* ═══════════════ CSV export ═══════════════ */
function exportCsv() {
  const headers = ["Title", "Type", "Status", "Provider", "Claim #", "Amount", "Incident Date", "Filed Date", "Tags", "Description", "Updated"];
  const cell = v => `"${String(v ?? "").replace(/"/g, '""')}"`;
  const rows = store.claims.map(c => [
    c.title, c.type, c.status, c.provider, c.claimNumber, c.amount ?? "",
    c.incidentDate, c.filedDate, (c.tags || []).join("; "), c.description, c.updatedAt,
  ].map(cell).join(","));
  const csv = "\uFEFF" + headers.map(cell).join(",") + "\n" + rows.join("\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
  const a = document.createElement("a");
  a.href = URL.createObjectURL(blob);
  a.download = `claims-${isoDate(Date.now())}.csv`;
  a.click();
  URL.revokeObjectURL(a.href);
  toast("CSV exported");
}

/* ═══════════════ Theme ═══════════════ */
function applyTheme(t) {
  document.documentElement.dataset.theme = t;
  $("#themeToggle").textContent = t === "dark" ? "☀️" : "🌙";
  localStorage.setItem(THEME_KEY, t);
}

/* ═══════════════ Global events ═══════════════ */
$("#newClaimBtn").addEventListener("click", () => openModal(null));
$("#emptyNewBtn").addEventListener("click", () => openModal(null));
$("#exportCsvBtn").addEventListener("click", exportCsv);
$("#themeToggle").addEventListener("click", () =>
  applyTheme(document.documentElement.dataset.theme === "dark" ? "light" : "dark"));

$("#searchInput").addEventListener("input", e => { ui.search = e.target.value; renderList(); });
$("#typeFilter").addEventListener("change", e => { ui.type = e.target.value; renderList(); });
$("#sortSelect").addEventListener("change", e => { ui.sort = e.target.value; renderList(); });

$("#statusChips").addEventListener("click", e => {
  const chip = e.target.closest("[data-status]");
  if (!chip) return;
  ui.status = ui.status === chip.dataset.status ? "" : chip.dataset.status;
  renderChips();
  renderList();
});

claimList.addEventListener("click", e => {
  const card = e.target.closest("[data-id]");
  if (card) openDrawer(card.dataset.id);
});
claimList.addEventListener("keydown", e => {
  if (e.key !== "Enter" && e.key !== " ") return;
  const card = e.target.closest("[data-id]");
  if (card) { e.preventDefault(); openDrawer(card.dataset.id); }
});

[claimModal, detailDrawer].forEach(ov =>
  ov.addEventListener("mousedown", e => { if (e.target === ov) ov === claimModal ? closeModal() : closeDrawer(); }));

document.querySelectorAll("[data-close-modal]").forEach(b => b.addEventListener("click", closeModal));

document.addEventListener("keydown", e => {
  if (e.key === "Escape") { closeModal(); closeDrawer(); }
});

/* ═══════════════ Init ═══════════════ */
applyTheme(localStorage.getItem(THEME_KEY) ||
  (matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light"));
store.load();
renderAll();
